sqlMap.select:
SELECT id as taskid, subject as taskname,ca.sub_object_id as workitemid FROM ctp_affair ca WHERE ca.sub_object_id in (SELECT wsc.workitem_id FROM wf_supernode_control wsc WHERE wsc.invoke_time IS NOT NULL AND wsc.return_time IS NOT NULL AND wsc.member_id <>util_user.getMemIdByLoginName('flowbot') AND ca.member_id in (SELECT ID FROM org_member)
wsc.invoke_time > SYSDATE - $timeLimit$
) and state = 3
